module top_module(
    input clock,
    input resetn,
    input valid_in,
    output valid_out,
    input stall_in,
    output stall_out
);reg invalid_data;
reg stall_out_reg;

always @(posedge clock or negedge resetn) begin
    if (~resetn) begin
        invalid_data <= 1'b0;
        stall_out_reg <= 1'b0;
    end else begin
        if (valid_in && ~stall_in) begin
            invalid_data <= 1'b1;
            stall_out_reg <= 1'b0;
        end else begin
            invalid_data <= 1'b0;
            stall_out_reg <= 1'b1;
        end
    end
end

assign valid_out = invalid_data;
assign stall_out = stall_out_reg;

endmodule
